module top_module(
  input [3:0] operand_a,
  input [3:0] num2,
  input [1:0] op,
  output reg [3:0] result
);always @(*) begin
    case(op)
      2'b00: result = operand_a + num2;
      2'b01: result = operand_a - num2;
      2'b10: result = operand_a * num2;
      2'b11: if(num2 == 0) result = 4'b0000;
             else result = operand_a / num2;
    endcase
  end

endmodule
